from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_jwt_extended import JWTManager, jwt_required, get_jwt_identity

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'  # Use your database URI here
app.config['JWT_SECRET_KEY'] = 'super-secret'  # Change this!
jwt = JWTManager(app)

db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    role = db.Column(db.String(30), default='user')
    account_status = db.Column(db.String(30), default='active')
    subscription_tier = db.Column(db.String(30), default='free')
    
@app.route('/api/users/<int:user_id>', methods=['PUT'])
@jwt_required()
def update_user(user_id):
    current_admin = get_jwt_identity()
    if not current_admin['role'] == 'admin':
        return jsonify({"msg": "Admins only!"}), 403
    
    user = User.query.get(user_id)
    if not user:
        return jsonify({"msg": "User not found."}), 404
        
    data = request.get_json()
    for key, value in data.items():
        setattr(user, key, value)
    
    db.session.commit()
    
    return jsonify({"msg": "User updated successfully."}), 200